const express = require('express');
const bodyParser = require('body-parser');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

let rewards = {
    1: { scoreThreshold: 100, reward: 'Bronze Medal' },
    2: { scoreThreshold: 200, reward: 'Silver Medal' },
    3: { scoreThreshold: 300, reward: 'Gold Medal' },
};

app.post('/complete-level', (req, res) => {
    const { level, score, time } = req.body;

    if (!level || !score || !time) {
        return res.status(400).json({ message: 'Invalid data' });
    }

    // Basic validation
    if (typeof score !== 'number' || typeof time !== 'number') {
        return res.status(400).json({ message: 'Score and time must be numbers' });
    }

    let reward = null;
    for (const key in rewards) {
        if (score >= rewards[key].scoreThreshold) {
            reward = rewards[key].reward;
        }
    }

    return res.status(200).json({ message: 'Level completed', reward });
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});